                  <td style="border: 1pt solid #000; padding: 6px; font-size: 8.5pt;"><b>${Yt.nombre}</b> ${Yt.fileName?`<br/><span style="font-size:7.5pt; color:#555;">[Archivo: ${Yt.fileName}]</span>`:""}</td>
